const input = $input.first().json.text;

if (!input || typeof input !== 'string') {
  throw new Error("Mensaje vacío o inválido");
}

return [{
  json: {
    output: input.result || "El mensaje contiene instrucciones invalidas que no cumple las políticas"
  }
}];

const allItems = $input.all();

const contenidos = allItems.map(item => item.json.document.pageContent);
const score = allItems.map(item => item.json.score);
const chat = $('Edit Fields').first().json.pregunta
//const sessionid = $('Telegram Trigger').first().json.message.chat.id

return [
  {
    json: {
      contenidos,
      score,
      chat,
      //sessionid
    }
  }
];

// Obtener respuestas de manera segura
const modelo1 = $('AI Agent1')?.first()?.json?.output;
const modelo2 = $('model check')?.first()?.json?.output;
const chat = $('Edit Fields').first().json.pregunta;

// Retornar solo un item (respuesta unificada)
return [
  {
    json: {
      respuestas_unidas: {
        modelo1,
        modelo2
      },
      chat
    }
  }
];

options.systemMessage:
Eres un evaluador experto de sistemas RAG (Retrieval-Augmented Generation). Evalúa si una respuesta es correcta basándote en:
1. Pregunta original: {{ chat }}
2. Respuesta del sistema: {{respuesta}}
3. Fragmentos recuperados con sus scores (0 a 1): {{#each contenidos}}
Fragmento {{@index}} (score: {{../score.[@index]}}):
{{this}}
{{/each}}

Instrucciones:
- Marca como "correcta": true solo si la respuesta está respaldada directamente por al menos un fragmento, aunque otros no sean relevantes  
-Explica brevemente qué fragmento(s) apoyan o contradicen la respuesta (máx. 5 lineas). 
-Si contradice o no está sustentada, marca "correcta": false.
-Ignora conocimiento externo, usa solo los fragmentos.

Formato de salida (texto plano):
"correcta": true/false, "Explicación breve basada en fragmentos."

