const input = $json;

if (input.platform === "telegram") {
  return [{
    json: {
      method: "telegram",
      chatId: input.sessionId,
      text: input.output
    }
  }];
} else if (input.platform === "evoapi") {
  return [{
    json: {
      method: "http",
      url: `${input.url_server}/message/sendText/${input.instance}`,
      headers: { apikey: input.apikey },
      body: {
        number: input.chat_id,
        text: input.output
      }
    }
  }];
}
